class FfiConverterUInt64: FfiConverter<ulong, ulong> {
    public static FfiConverterUInt64 INSTANCE = new FfiConverterUInt64();

    public override ulong Lift(ulong value) {
        return value;
    }

    public override ulong Read(BigEndianStream stream) {
        return stream.ReadULong();
    }

    public override ulong Lower(ulong value) {
        return value;
    }

    public override int AllocationSize(ulong value) {
        return 8;
    }

    public override void Write(ulong value, BigEndianStream stream) {
        stream.WriteULong(value);
    }
}



class FfiConverterDouble: FfiConverter<double, double> {
    public static FfiConverterDouble INSTANCE = new FfiConverterDouble();

    public override double Lift(double value) {
        return value;
    }

    public override double Read(BigEndianStream stream) {
        return stream.ReadDouble();
    }

    public override double Lower(double value) {
        return value;
    }

    public override int AllocationSize(double value) {
        return 8;
    }

    public override void Write(double value, BigEndianStream stream) {
        stream.WriteDouble(value);
    }
}



class FfiConverterString: FfiConverter<string, RustBuffer> {
    public static FfiConverterString INSTANCE = new FfiConverterString();

    // Note: we don't inherit from FfiConverterRustBuffer, because we use a
    // special encoding when lowering/lifting.  We can use `RustBuffer.len` to
    // store our length and avoid writing it out to the buffer.
    public override string Lift(RustBuffer value) {
        try {
            var bytes = value.AsStream().ReadBytes(Convert.ToInt32(value.len));
            return System.Text.Encoding.UTF8.GetString(bytes);
        } finally {
            RustBuffer.Free(value);
        }
    }

    public override string Read(BigEndianStream stream) {
        var length = stream.ReadInt();
        var bytes = stream.ReadBytes(length);
        return System.Text.Encoding.UTF8.GetString(bytes);
    }

    public override RustBuffer Lower(string value) {
        var bytes = System.Text.Encoding.UTF8.GetBytes(value);
        var rbuf = RustBuffer.Alloc(bytes.Length);
        rbuf.AsWriteableStream().WriteBytes(bytes);
        return rbuf;
    }

    // TODO(CS)
    // We aren't sure exactly how many bytes our string will be once it's UTF-8
    // encoded.  Allocate 3 bytes per unicode codepoint which will always be
    // enough.
    public override int AllocationSize(string value) {
        const int sizeForLength = 4;
        var sizeForString = System.Text.Encoding.UTF8.GetByteCount(value);
        return sizeForLength + sizeForString;
    }

    public override void Write(string value, BigEndianStream stream) {
        var bytes = System.Text.Encoding.UTF8.GetBytes(value);
        stream.WriteInt(bytes.Length);
        stream.WriteBytes(bytes);
    }
}



/// <summary>
/// Compact view of the quote endpoint's response. Mirrors
/// `lendaswap_sdk::types::QuoteResponse` minus the wire-only fields
/// that aren't useful to a non-Rust caller.
///
/// Large monetary quantities stay as strings (matching the backend's
/// wire format) to side-step JS-style number-precision issues and let
/// callers parse with whatever big-int library they prefer.
/// </summary>
internal record QuoteResult (
    string @exchangeRate, 
    ulong @networkFee, 
    ulong @gaslessNetworkFee, 
    ulong @protocolFee, 
    double @protocolFeeRate, 
    ulong @minAmount, 
    ulong @maxAmount, 
    string @sourceAmount, 
    string @targetAmount, 
    string @netSourceAmount, 
    string @netTargetAmount, 
    ulong? @bridgeFee
) {
}

class FfiConverterTypeQuoteResult: FfiConverterRustBuffer<QuoteResult> {
    public static FfiConverterTypeQuoteResult INSTANCE = new FfiConverterTypeQuoteResult();

    public override QuoteResult Read(BigEndianStream stream) {
        return new QuoteResult(
            @exchangeRate: FfiConverterString.INSTANCE.Read(stream),
            @networkFee: FfiConverterUInt64.INSTANCE.Read(stream),
            @gaslessNetworkFee: FfiConverterUInt64.INSTANCE.Read(stream),
            @protocolFee: FfiConverterUInt64.INSTANCE.Read(stream),
            @protocolFeeRate: FfiConverterDouble.INSTANCE.Read(stream),
            @minAmount: FfiConverterUInt64.INSTANCE.Read(stream),
            @maxAmount: FfiConverterUInt64.INSTANCE.Read(stream),
            @sourceAmount: FfiConverterString.INSTANCE.Read(stream),
            @targetAmount: FfiConverterString.INSTANCE.Read(stream),
            @netSourceAmount: FfiConverterString.INSTANCE.Read(stream),
            @netTargetAmount: FfiConverterString.INSTANCE.Read(stream),
            @bridgeFee: FfiConverterOptionalUInt64.INSTANCE.Read(stream)
        );
    }

    public override int AllocationSize(QuoteResult value) {
        return 0
            + FfiConverterString.INSTANCE.AllocationSize(value.@exchangeRate)
            + FfiConverterUInt64.INSTANCE.AllocationSize(value.@networkFee)
            + FfiConverterUInt64.INSTANCE.AllocationSize(value.@gaslessNetworkFee)
            + FfiConverterUInt64.INSTANCE.AllocationSize(value.@protocolFee)
            + FfiConverterDouble.INSTANCE.AllocationSize(value.@protocolFeeRate)
            + FfiConverterUInt64.INSTANCE.AllocationSize(value.@minAmount)
            + FfiConverterUInt64.INSTANCE.AllocationSize(value.@maxAmount)
            + FfiConverterString.INSTANCE.AllocationSize(value.@sourceAmount)
            + FfiConverterString.INSTANCE.AllocationSize(value.@targetAmount)
            + FfiConverterString.INSTANCE.AllocationSize(value.@netSourceAmount)
            + FfiConverterString.INSTANCE.AllocationSize(value.@netTargetAmount)
            + FfiConverterOptionalUInt64.INSTANCE.AllocationSize(value.@bridgeFee);
    }

    public override void Write(QuoteResult value, BigEndianStream stream) {
            FfiConverterString.INSTANCE.Write(value.@exchangeRate, stream);
            FfiConverterUInt64.INSTANCE.Write(value.@networkFee, stream);
            FfiConverterUInt64.INSTANCE.Write(value.@gaslessNetworkFee, stream);
            FfiConverterUInt64.INSTANCE.Write(value.@protocolFee, stream);
            FfiConverterDouble.INSTANCE.Write(value.@protocolFeeRate, stream);
            FfiConverterUInt64.INSTANCE.Write(value.@minAmount, stream);
            FfiConverterUInt64.INSTANCE.Write(value.@maxAmount, stream);
            FfiConverterString.INSTANCE.Write(value.@sourceAmount, stream);
            FfiConverterString.INSTANCE.Write(value.@targetAmount, stream);
            FfiConverterString.INSTANCE.Write(value.@netSourceAmount, stream);
            FfiConverterString.INSTANCE.Write(value.@netTargetAmount, stream);
            FfiConverterOptionalUInt64.INSTANCE.Write(value.@bridgeFee, stream);
    }
}



/// <summary>
/// Version reported by the backend (`GET /version`). Mirrors
/// `lendaswap_sdk::types::Version` — copied here as a `uniffi::Record`
/// so the FFI surface owns its own data shape and can evolve
/// independently of the Rust type.
/// </summary>
internal record Version (
    string @tag, 
    string @commitHash
) {
}

class FfiConverterTypeVersion: FfiConverterRustBuffer<Version> {
    public static FfiConverterTypeVersion INSTANCE = new FfiConverterTypeVersion();

    public override Version Read(BigEndianStream stream) {
        return new Version(
            @tag: FfiConverterString.INSTANCE.Read(stream),
            @commitHash: FfiConverterString.INSTANCE.Read(stream)
        );
    }

    public override int AllocationSize(Version value) {
        return 0
            + FfiConverterString.INSTANCE.AllocationSize(value.@tag)
            + FfiConverterString.INSTANCE.AllocationSize(value.@commitHash);
    }

    public override void Write(Version value, BigEndianStream stream) {
            FfiConverterString.INSTANCE.Write(value.@tag, stream);
            FfiConverterString.INSTANCE.Write(value.@commitHash, stream);
    }
}





/// <summary>
/// Chain identifiers exposed across FFI. Mirrors
/// `lendaswap_sdk::types::Chain` — the underlying SDK type can't carry
/// `#[derive(uniffi::Enum)]` itself (uniffi only derives on types in
/// this crate), so we redefine here and bridge via `From`.
///
/// `Other` is the forward-compat escape hatch: any wire value the SDK
/// doesn't recognise round-trips through it without losing fidelity.
/// </summary>
public record ChainId {
    
    public record Polygon: ChainId {}
    
    
    public record Ethereum: ChainId {}
    
    
    public record Arbitrum: ChainId {}
    
    
    public record Arkade: ChainId {}
    
    
    public record Lightning: ChainId {}
    
    
    public record Bitcoin: ChainId {}
    
    
    public record Other (
        string @wire
    ) : ChainId {}
    

    
}

class FfiConverterTypeChainId : FfiConverterRustBuffer<ChainId>{
    public static FfiConverterRustBuffer<ChainId> INSTANCE = new FfiConverterTypeChainId();

    public override ChainId Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1:
                return new ChainId.Polygon(
                );
            case 2:
                return new ChainId.Ethereum(
                );
            case 3:
                return new ChainId.Arbitrum(
                );
            case 4:
                return new ChainId.Arkade(
                );
            case 5:
                return new ChainId.Lightning(
                );
            case 6:
                return new ChainId.Bitcoin(
                );
            case 7:
                return new ChainId.Other(
                    FfiConverterString.INSTANCE.Read(stream)
                );
            default:
                throw new InternalException(String.Format("invalid enum value '{0}' in FfiConverterTypeChainId.Read()", value));
        }
    }

    public override int AllocationSize(ChainId value) {
        switch (value) {
            case ChainId.Polygon variant_value:
                return 4;
            case ChainId.Ethereum variant_value:
                return 4;
            case ChainId.Arbitrum variant_value:
                return 4;
            case ChainId.Arkade variant_value:
                return 4;
            case ChainId.Lightning variant_value:
                return 4;
            case ChainId.Bitcoin variant_value:
                return 4;
            case ChainId.Other variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@wire);
            default:
                throw new InternalException(String.Format("invalid enum value '{0}' in FfiConverterTypeChainId.AllocationSize()", value));
        }
    }

    public override void Write(ChainId value, BigEndianStream stream) {
        switch (value) {
            case ChainId.Polygon variant_value:
                stream.WriteInt(1);
                break;
            case ChainId.Ethereum variant_value:
                stream.WriteInt(2);
                break;
            case ChainId.Arbitrum variant_value:
                stream.WriteInt(3);
                break;
            case ChainId.Arkade variant_value:
                stream.WriteInt(4);
                break;
            case ChainId.Lightning variant_value:
                stream.WriteInt(5);
                break;
            case ChainId.Bitcoin variant_value:
                stream.WriteInt(6);
                break;
            case ChainId.Other variant_value:
                stream.WriteInt(7);
                FfiConverterString.INSTANCE.Write(variant_value.@wire, stream);
                break;
            default:
                throw new InternalException(String.Format("invalid enum value '{0}' in FfiConverterTypeChainId.Write()", value));
        }
    }
}







/// <summary>
/// Source / target amount mutex. Mirrors `lendaswap_sdk::types::QuoteAmount`
/// — encoding the invariant at the type level means the FFI surface no
/// longer needs the "exactly one of two Options" runtime check.
/// </summary>
public record QuoteAmount {
    
    /// <summary>
    /// Amount in the smallest unit of the source token.
    /// </summary>
    public record Source (
        ulong @units
    ) : QuoteAmount {}
    
    /// <summary>
    /// Amount in the smallest unit of the target token.
    /// </summary>
    public record Target (
        ulong @units
    ) : QuoteAmount {}
    

    
}

class FfiConverterTypeQuoteAmount : FfiConverterRustBuffer<QuoteAmount>{
    public static FfiConverterRustBuffer<QuoteAmount> INSTANCE = new FfiConverterTypeQuoteAmount();

    public override QuoteAmount Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1:
                return new QuoteAmount.Source(
                    FfiConverterUInt64.INSTANCE.Read(stream)
                );
            case 2:
                return new QuoteAmount.Target(
                    FfiConverterUInt64.INSTANCE.Read(stream)
                );
            default:
                throw new InternalException(String.Format("invalid enum value '{0}' in FfiConverterTypeQuoteAmount.Read()", value));
        }
    }

    public override int AllocationSize(QuoteAmount value) {
        switch (value) {
            case QuoteAmount.Source variant_value:
                return 4
                    + FfiConverterUInt64.INSTANCE.AllocationSize(variant_value.@units);
            case QuoteAmount.Target variant_value:
                return 4
                    + FfiConverterUInt64.INSTANCE.AllocationSize(variant_value.@units);
            default:
                throw new InternalException(String.Format("invalid enum value '{0}' in FfiConverterTypeQuoteAmount.AllocationSize()", value));
        }
    }

    public override void Write(QuoteAmount value, BigEndianStream stream) {
        switch (value) {
            case QuoteAmount.Source variant_value:
                stream.WriteInt(1);
                FfiConverterUInt64.INSTANCE.Write(variant_value.@units, stream);
                break;
            case QuoteAmount.Target variant_value:
                stream.WriteInt(2);
